// Normalize Telegram update into a flat object for downstream routing.
const raw = $input.item.json;
const msg = raw.message;
const cb = raw.callback_query;

let kind = 'other';
let user, chat_id, text, callback_data, callback_id, message_id;
let is_voice = false;
let voice_file_id = null;
let voice_mime = null;

if (cb) {
  kind = 'callback_query';
  user = cb.from;
  chat_id = cb.message.chat.id;
  message_id = cb.message.message_id;
  callback_data = cb.data || '';
  callback_id = cb.id;
} else if (msg) {
  kind = 'message';
  user = msg.from;
  chat_id = msg.chat.id;
  message_id = msg.message_id;
  text = (msg.text || '').trim();
  if (msg.voice) {
    is_voice = true;
    voice_file_id = msg.voice.file_id;
    voice_mime = msg.voice.mime_type || 'audio/ogg';
  } else if (msg.audio) {
    is_voice = true;
    voice_file_id = msg.audio.file_id;
    voice_mime = msg.audio.mime_type || 'audio/mpeg';
  }
}

if (!user) {
  return [];
}

// Parse callback_data of form 'action' or 'action:param'
let cb_action = '';
let cb_param = '';
if (callback_data) {
  const idx = callback_data.indexOf(':');
  if (idx === -1) {
    cb_action = callback_data;
  } else {
    cb_action = callback_data.slice(0, idx);
    cb_param = callback_data.slice(idx + 1);
  }
}

return [{
  json: {
    kind,
    telegram_user_id: user.id,
    username: user.username || null,
    first_name: user.first_name || null,
    last_name: user.last_name || null,
    chat_id,
    message_id,
    text: text || '',
    is_voice,
    voice_file_id,
    voice_mime,
    is_command: text ? text.startsWith('/') : false,
    command: text && text.startsWith('/') ? text.split(/\s+/)[0].split('@')[0] : '',
    callback_data,
    callback_id,
    cb_action,
    cb_param
  }
}];

