const item = $input.first();
const bin = item.binary && item.binary.data;
let b64 = '';
let mime = 'audio/ogg';
if (bin) {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  b64 = buf.toString('base64');
  mime = bin.mimeType || mime;
}
if (mime === 'application/octet-stream') mime = 'audio/ogg';
const pu = $('Parse Update').first().json;
return [{ json: { audio_b64: b64, audio_mime: mime, telegram_user_id: pu.telegram_user_id, chat_id: pu.chat_id } }];

const pu = $('Parse Update').first().json;
const row = $('AI: Get User Agents').first().json;
let agents = [];
try { agents = (typeof row.agents_json === 'string') ? JSON.parse(row.agents_json) : (row.agents_json || []); } catch(e) {}

let userText = (pu.text || '').trim();

if (pu.is_voice) {
  try {
    const up = $input.first().json;
    const t = up && up.candidates && up.candidates[0] && up.candidates[0].content && up.candidates[0].content.parts && up.candidates[0].content.parts[0] && up.candidates[0].content.parts[0].text;
    if (t) userText = String(t).trim();
  } catch (e) {}
}

const agentsList = agents.length
  ? agents.map(a => `- ${a.name} (elevenlabs_id=${a.elevenlabs_agent_id})`).join('\n')
  : '(none yet — user can use /add to create one)';

const systemMessage = `You are an AI assistant inside a Telegram bot. You help the user manage their ElevenLabs Conversational AI voice agents.

Each agent has three editable fields:
- prompt: system prompt defining behavior, role, personality
- welcome (first_message): the first message the agent says when a conversation starts
- knowledge_base: text documents the agent can reference during conversations

The user owns these agents:
${agentsList}

You have these tools:
- get_agent_config(agentId): get current prompt, welcome message, knowledge base of an agent
- update_agent_prompt(agentId, newPrompt): replace the agent's system prompt
- update_agent_welcome(agentId, newFirstMessage): replace the agent's welcome message
- create_knowledge_doc(docName, docText): create a knowledge document, returns its document id
- attach_knowledge_to_agent(agentId, docId, docName): attach a knowledge doc to an agent

Rules:
- agentId must be a value from the agent list above (the elevenlabs_id, starts with "agent_"). Never invent IDs.
- To replace the knowledge base: call create_knowledge_doc first to get a docId, then call attach_knowledge_to_agent.
- If the user does not name an agent and owns several, ask which one. If only one, use it.
- Respond in the user's language. Be concise. After a successful update, confirm in one short sentence.`;

return [{ json: { user_text: userText, system_message: systemMessage, chat_id: pu.chat_id, telegram_user_id: pu.telegram_user_id } }];

const args = (typeof query === 'string') ? JSON.parse(query) : query;
const agentId = args.agentId;
const res = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.elevenlabs.io/v1/convai/agents/' + agentId,
  headers: { 'xi-api-key': $env.ELEVENLABS_API_KEY },
  json: true,
});
const cfg = (res.conversation_config && res.conversation_config.agent) || {};
const out = {
  prompt: (cfg.prompt && cfg.prompt.prompt) || '',
  first_message: cfg.first_message || '',
  knowledge_base: (cfg.prompt && cfg.prompt.knowledge_base) || [],
};
return JSON.stringify(out);

